// Some portions generated by Claude
package org.eclipse.rdf4j.query.algebra.equivalence.internal;

import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertTrue;

import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.ValueFactory;
import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.query.algebra.Distinct;
import org.eclipse.rdf4j.query.algebra.Extension;
import org.eclipse.rdf4j.query.algebra.ExtensionElem;
import org.eclipse.rdf4j.query.algebra.Join;
import org.eclipse.rdf4j.query.algebra.StatementPattern;
import org.eclipse.rdf4j.query.algebra.Union;
import org.eclipse.rdf4j.query.algebra.ValueConstant;
import org.eclipse.rdf4j.query.algebra.Var;
import org.eclipse.rdf4j.query.algebra.equivalence.CheckOptions;
import org.eclipse.rdf4j.query.algebra.equivalence.SemanticSummary;
import org.junit.jupiter.api.Test;

/** Regression pins for semantic facts the analyzer used to get wrong. */
class SemanticAnalyzerImplRegressionTest {
	private static final ValueFactory VF = SimpleValueFactory.getInstance();
	private static final IRI P1 = VF.createIRI("urn:test:p1");
	private static final IRI P2 = VF.createIRI("urn:test:p2");

	private final SemanticAnalyzerImpl analyzer = new SemanticAnalyzerImpl(CheckOptions.defaults());

	@Test
	void equalsInvisibleScopeFlagIsNotDroppedByScanDeduplication() {
		// The two unions are equals()-equal (BinaryTupleOperator.equals ignores the scope flag), so a
		// value-equality visited set would skip the scoped one and lose its correlation sensitivity.
		Union plain = new Union(pattern("s", P1, "o"), pattern("s", P2, "o"));
		Union scoped = new Union(pattern("s", P1, "o"), pattern("s", P2, "o"));
		scoped.setVariableScopeChange(true);

		SemanticSummary summary = analyzer.analyze(new Join(plain, scoped));

		assertTrue(summary.correlationSensitive());
	}

	@Test
	void extensionOverwriteIsNotDuplicateFree() {
		// ExtensionIterator overwrites an already-bound name, which can collapse distinct input rows
		// into identical output rows.
		Extension overwrite = new Extension(
				new Distinct(pattern("s", P1, "x")),
				new ExtensionElem(new ValueConstant(VF.createLiteral("A")), "x"));

		assertFalse(analyzer.analyze(overwrite).duplicateFree());
	}

	@Test
	void extensionBindingFreshNameKeepsDuplicateFreedom() {
		Extension fresh = new Extension(
				new Distinct(pattern("s", P1, "o")),
				new ExtensionElem(new ValueConstant(VF.createLiteral("A")), "fresh"));

		assertTrue(analyzer.analyze(fresh).duplicateFree());
	}

	private static StatementPattern pattern(String subjectName, IRI predicate, String objectName) {
		return new StatementPattern(
				Var.of(subjectName),
				Var.of("const-" + predicate.stringValue(), predicate),
				Var.of(objectName));
	}
}
